import React, { useState } from 'react';
import './Header.css';

export default function Header() {
  const [search, setSearch] = useState('');
  const now = new Date();
  const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

  return (
    <header className="header">
      <div className="header-left">
        <h1 className="page-title">Dashboard</h1>
        <span className="header-date">{dateStr}</span>
      </div>
      <div className="header-right">
        <div className="search-box">
          <svg width="15" height="15" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search anything…" />
          <kbd>⌘K</kbd>
        </div>
        <button className="icon-btn">
          <svg width="17" height="17" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
          </svg>
          <span className="notif-dot" />
        </button>
        <button className="period-btn active">7D</button>
        <button className="period-btn">30D</button>
        <button className="period-btn">90D</button>
      </div>
    </header>
  );
}
